import React from 'react';
import Logo from './Logo';
import BurgerMenu from './BurgerMenu';
// import '../styles/Header.css';

const Header: React.FC = () => {
    return (
        <header className="header">
            <div className="logo-container">
                <Logo />
                <div className="site-text">
                    <h1 className="site-name">RTP Upholstery</h1>
                    <h4 className="site-subtitle">◆ Research Triangle Park Area</h4>
                </div>
            </div>

            <div className="header-actions">
                <a href="https://facebook.com" target="_blank" rel="noreferrer" className="header-icon-link" aria-label="Visit our Facebook page">
                    f
                </a>
                <a href="https://instagram.com" target="_blank" rel="noreferrer" className="header-icon-link" aria-label="Visit our Instagram page">
                    ○
                </a>
                <a href="https://maps.google.com" target="_blank" rel="noreferrer" className="header-icon-link" aria-label="Open Google Maps">
                    ⌖
                </a>
                <BurgerMenu />
            </div>
        </header>
    );
};

export default Header;
